//! Typed identifiers for cards and monsters.
//!
//! The `define_ids!` macro below expands each table row into `as_str`,
//! `from_str`, `sts2_id`, `from_sts2`, and `all` — all O(1) match arms.
//!
//! **Do not edit the generated regions by hand.** Edit `data/cards.toml` or
//! `data/monsters.toml` and run `python scripts/gen_ids.py`.
//! After adding a variant, also add its card/monster logic in cards.rs / monsters.rs.

macro_rules! define_ids {
    ($name:ident { $($variant:ident => $display:literal / $sts2:literal),* $(,)? }) => {
        #[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
        pub enum $name { $($variant),* }

        impl $name {
            /// Canonical sim display name.
            pub fn as_str(self) -> &'static str {
                match self { $($name::$variant => $display),* }
            }
            /// Parse from sim display name. Returns `None` for unknown names.
            pub fn from_str(s: &str) -> Option<Self> {
                match s { $($display => Some($name::$variant),)* _ => None }
            }
            /// STS2 model ID (screaming snake case).
            pub fn sts2_id(self) -> &'static str {
                match self { $($name::$variant => $sts2),* }
            }
            /// Parse from STS2 model ID. Returns `None` for unknown IDs.
            pub fn from_sts2(s: &str) -> Option<Self> {
                match s { $($sts2 => Some($name::$variant),)* _ => None }
            }
            /// Every variant, in declaration order.
            pub fn all() -> &'static [Self] {
                &[$($name::$variant),*]
            }
        }
    };
}

