#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn card_id_round_trips() {
        assert_eq!(CardId::all().len(), 79);
        for &v in CardId::all() {
            assert_eq!(CardId::from_str(v.as_str()), Some(v), "from_str round-trip failed for {:?}", v);
            assert_eq!(CardId::from_sts2(v.sts2_id()), Some(v), "from_sts2 round-trip failed for {:?}", v);
        }
    }

    #[test]
    fn monster_id_round_trips() {
        assert_eq!(MonsterId::all().len(), 31);
        for &v in MonsterId::all() {
            assert_eq!(MonsterId::from_str(v.as_str()), Some(v), "from_str round-trip failed for {:?}", v);
            assert_eq!(MonsterId::from_sts2(v.sts2_id()), Some(v), "from_sts2 round-trip failed for {:?}", v);
        }
    }
}
